mapper.select:
select cos.id, cos.create_time, cos.order_no, cos.user_id, cos.merchant_id, cos.real_price, cos.settlement_amount, cos.state, cos.payment_type,
		cos.payment_state, cos.remarks, col.logistics_no, su.username as username, cmi.merchant_name,
CONCAT((select city_name from city_code where city_id = uas.province_code),
(select city_name from city_code where city_id = uas.city_code),
(select city_name from city_code where city_id = uas.country_code), uas.address, uas.concat_person) as address_detail
from cm_order_shopping cos
left join cm_customer su on cos.user_id = su.user_id
left join cm_order_logistics col on cos.order_no = col.shopping_order_no
left join cm_merchant_info cmi on cos.merchant_id = cmi.id
left join cm_user_address uas on uas.id = cos.user_address_id
where cos.deleted = '0'

	and cos.merchant_id = #{vo.merchantId}


	and cos.order_no = #{vo.orderNo}


	and su.username = #{vo.username}


	and cos.state = #{vo.state}


	and cos.create_time >= #{vo.createTimeStart}


	and cos.create_time < #{vo.createTimeEnd}

order by cos.create_time desc
